const CONFIG = {
  timezone: 'Asia/Jerusalem',
  urgencyKeywords: {
    critical: ['urgent', 'asap', 'immediately', 'critical', 'emergency', 'דחוף', 'מיידי'],
    high: ['deadline', 'due', 'must', 'required', 'payment', 'invoice', 'action required', 'תאריך יעד', 'תשלום'],
    medium: ['meeting', 'reminder', 'review', 'submit', 'approval', 'פגישה', 'תזכורת'],
    low: ['fyi', 'update', 'info', 'notice', 'newsletter', 'עדכון']
  }
};

function esc(text) {
  return (text || '').replace(/([\[\]_*`~])/g, '\\$1');
}

function fmtTime(iso) {
  if (!iso) return null;
  return new Date(iso).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', timeZone: CONFIG.timezone });
}

function getEmailUrgency(text) {
  const lower = (text || '').toLowerCase();
  if (CONFIG.urgencyKeywords.critical.some(w => lower.includes(w))) return '🔴';
  if (CONFIG.urgencyKeywords.high.some(w => lower.includes(w))) return '🟠';
  if (CONFIG.urgencyKeywords.medium.some(w => lower.includes(w))) return '🟡';
  return '⚪';
}

function getSender(item) {
  let from = item.from || item.From || '';
  if ((!from || !from.includes('@')) && item.payload?.headers) {
    const h = item.payload.headers.find(h => h.name?.toLowerCase() === 'from');
    if (h?.value) from = h.value;
  }
  const nameMatch = from.match(/^([^<]+)\s*</);
  return nameMatch ? nameMatch[1].trim() : from.split('@')[0] || 'Unknown';
}

// --- Build today's date header ---
const now = new Date();
const dateStr = now.toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: CONFIG.timezone });
const greeting = (() => {
  const hour = parseInt(now.toLocaleString('en-GB', { hour: 'numeric', hour12: false, timeZone: CONFIG.timezone }));
  if (hour < 12) return '🌅 Good Morning';
  if (hour < 17) return '☀️ Good Afternoon';
  return '🌙 Good Evening';
})();

let msg = `${greeting}, Alex!\n📆 *${dateStr}*\n`;

// --- Separate calendar items from email items ---
const allItems = $input.all();

// Calendar items have start.dateTime or start.date
const events = allItems.filter(i => i.json?.start?.dateTime || i.json?.start?.date);

// Email items have threadId or labelIds (Gmail-specific fields)
const emails = allItems.filter(i => i.json?.threadId || i.json?.labelIds);

// --- Calendar Section ---
msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msg += `📅 *TODAY'S SCHEDULE*`;

if (events.length === 0) {
  msg += `\nNo events today ✨\n`;
} else {
  const seen = new Set();
  const uniqueEvents = events.filter(i => {
    const id = i.json.id || i.json.summary;
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });

  msg += ` (${uniqueEvents.length} event${uniqueEvents.length > 1 ? 's' : ''})\n`;
  for (const item of uniqueEvents) {
    const ev = item.json;
    const startISO = ev.start?.dateTime || ev.start?.date;
    const endISO = ev.end?.dateTime || ev.end?.date;
    const startTime = fmtTime(startISO);
    const endTime = fmtTime(endISO);
    const isAllDay = !ev.start?.dateTime;
    const summary = ev.summary || 'Untitled';

    if (isAllDay) {
      msg += `\n🔹 *${esc(summary)}* — All day\n`;
    } else {
      msg += `\n🔹 *${esc(summary)}*\n`;
      msg += `    🕒 ${startTime} - ${endTime}\n`;
    }

    if (ev.hangoutLink) {
      msg += `    🎥 [Join Meet](${ev.hangoutLink})\n`;
    } else if (ev.location && ev.location.toLowerCase().includes('zoom')) {
      const zoomLink = ev.location.match(/https?:\/\/[^\s]+zoom[^\s]+/i);
      if (zoomLink) msg += `    🎥 [Join Zoom](${zoomLink[0]})\n`;
    } else if (ev.location && !ev.location.startsWith('http')) {
      msg += `    📍 ${esc(ev.location)}\n`;
    }

    const attendees = (ev.attendees || []).filter(a => !a.self);
    if (attendees.length > 0) {
      msg += `    👥 ${attendees.length} attendee${attendees.length > 1 ? 's' : ''}\n`;
    }
  }
}

// --- Email Section ---
msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msg += `📧 *UNREAD EMAILS*`;

// Deduplicate emails
const seenEmails = new Set();
const uniqueEmails = emails.filter(i => {
  const id = i.json.id || i.json.threadId;
  if (seenEmails.has(id)) return false;
  seenEmails.add(id);
  return true;
});

if (uniqueEmails.length === 0) {
  msg += `\nInbox zero! 🎉\n`;
} else {
  msg += ` (${uniqueEmails.length})\n`;
  const sorted = uniqueEmails.map(i => {
    const subj = i.json.subject || i.json.Subject || 'No Subject';
    const snippet = i.json.snippet || '';
    const urgency = getEmailUrgency(`${subj} ${snippet}`);
    const sender = getSender(i.json);
    return { urgency, subject: subj, sender, id: i.json.id };
  }).sort((a, b) => {
    const order = { '🔴': 0, '🟠': 1, '🟡': 2, '⚪': 3 };
    return (order[a.urgency] ?? 4) - (order[b.urgency] ?? 4);
  });

  const shown = sorted.slice(0, 8);
  for (const e of shown) {
    const shortSubj = e.subject.length > 50 ? e.subject.substring(0, 47) + '...' : e.subject;
    msg += `\n${e.urgency} [${esc(shortSubj)}](https://mail.google.com/mail/u/0/#inbox/${e.id})\n`;
    msg += `    👤 ${esc(e.sender)}\n`;
  }
  if (sorted.length > 8) {
    msg += `\n_...and ${sorted.length - 8} more_\n`;
  }
}

msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msg += `Have a great day! 💪`;

return [{ json: { reminderMessage: msg, messageType: 'morning_briefing' } }];

const CONFIG = { timezone: 'Asia/Jerusalem' };

function esc(text) {
  return (text || '').replace(/([\[\]_*`~])/g, '\\$1');
}

function fmtTime(iso) {
  if (!iso) return null;
  return new Date(iso).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', timeZone: CONFIG.timezone });
}

const calItems = $input.all();
const events = calItems.filter(i => !i.json?.error && (i.json?.start?.dateTime || i.json?.start?.date));

const now = new Date();
const weekStart = now.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', timeZone: CONFIG.timezone });
const weekEndDate = new Date(Date.now() + 7 * 86400000);
const weekEnd = weekEndDate.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', timeZone: CONFIG.timezone });

let msg = `📋 *Weekly Schedule*\n${weekStart} → ${weekEnd}\n`;

if (events.length === 0) {
  msg += `\nNo events this week! 🏖️\n`;
} else {
  const byDay = {};
  const dayOrder = [];
  for (const item of events) {
    const ev = item.json;
    const startISO = ev.start?.dateTime || ev.start?.date;
    const dayKey = new Date(startISO).toLocaleDateString('en-GB', {
      weekday: 'long', day: 'numeric', month: 'short', timeZone: CONFIG.timezone
    });
    if (!byDay[dayKey]) {
      byDay[dayKey] = [];
      dayOrder.push(dayKey);
    }
    byDay[dayKey].push(ev);
  }

  for (const day of dayOrder) {
    const dayEvents = byDay[day];
    msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
    msg += `📆 *${day}* (${dayEvents.length} event${dayEvents.length > 1 ? 's' : ''})\n`;

    for (const ev of dayEvents) {
      const startISO = ev.start?.dateTime || ev.start?.date;
      const endISO = ev.end?.dateTime || ev.end?.date;
      const isAllDay = !ev.start?.dateTime;
      const summary = ev.summary || 'Untitled';

      if (isAllDay) {
        msg += `  🔹 *${esc(summary)}* — All day\n`;
      } else {
        const startTime = fmtTime(startISO);
        const endTime = fmtTime(endISO);
        msg += `  🔹 *${esc(summary)}* ${startTime}-${endTime}\n`;
      }
    }
  }
}

msg += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msg += `Total: ${events.length} events this week`;

return [{ json: { reminderMessage: msg, messageType: 'weekly_summary' } }];

const CONFIG = {
  timezone: 'Asia/Jerusalem',
  urgencyKeywords: {
    critical: ['urgent', 'asap', 'immediately', 'critical', 'emergency', 'דחוף', 'מיידי'],
    high: ['deadline', 'due', 'must', 'required', 'payment', 'invoice', 'action required', 'תאריך יעד', 'תשלום'],
    medium: ['meeting', 'reminder', 'review', 'submit', 'approval', 'פגישה', 'תזכורת'],
    low: ['fyi', 'update', 'info', 'notice', 'newsletter', 'עדכון']
  }
};

function esc(text) {
  return (text || '').replace(/([\[\]_*`~])/g, '\\$1');
}

function getCategory(text) {
  const lower = (text || '').toLowerCase();
  if (CONFIG.urgencyKeywords.critical.some(w => lower.includes(w))) return { icon: '🔴', label: 'Urgent', order: 0 };
  if (CONFIG.urgencyKeywords.high.some(w => lower.includes(w))) return { icon: '🟠', label: 'Action Required', order: 1 };
  if (CONFIG.urgencyKeywords.medium.some(w => lower.includes(w))) return { icon: '🟡', label: 'Follow Up', order: 2 };
  if (CONFIG.urgencyKeywords.low.some(w => lower.includes(w))) return { icon: '🟢', label: 'FYI', order: 3 };
  return { icon: '⚪', label: 'Other', order: 4 };
}

function getSender(item) {
  let from = item.from || item.From || '';
  if ((!from || !from.includes('@')) && item.payload?.headers) {
    const h = item.payload.headers.find(h => h.name?.toLowerCase() === 'from');
    if (h?.value) from = h.value;
  }
  const nameMatch = from.match(/^([^<]+)\s*</);
  return nameMatch ? nameMatch[1].trim() : from.split('@')[0] || 'Unknown';
}

const emailItems = $input.all();
const emails = emailItems.filter(i => !i.json?.error && i.json?.id);

let msg = `📬 *Evening Email Digest*\n`;
const now = new Date();
msg += `${now.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'short', timeZone: CONFIG.timezone })}\n`;

if (emails.length === 0) {
  msg += `\nAll caught up! No unread emails. 🎉\n`;
} else {
  const categorized = emails.map(i => {
    const subj = i.json.subject || 'No Subject';
    const snippet = i.json.snippet || '';
    const cat = getCategory(`${subj} ${snippet}`);
    return { ...cat, subject: subj, sender: getSender(i.json), id: i.json.id, snippet };
  });

  const groups = {};
  for (const e of categorized) {
    if (!groups[e.label]) groups[e.label] = { icon: e.icon, order: e.order, items: [] };
    groups[e.label].items.push(e);
  }

  const sortedGroups = Object.entries(groups).sort((a, b) => a[1].order - b[1].order);

  msg += `\n📊 *${emails.length} unread email${emails.length > 1 ? 's' : ''}*\n`;

  for (const [label, group] of sortedGroups) {
    msg += `\n${group.icon} *${label}* (${group.items.length})\n`;
    const shown = group.items.slice(0, 5);
    for (const e of shown) {
      const shortSubj = e.subject.length > 45 ? e.subject.substring(0, 42) + '...' : e.subject;
      msg += `  • ${esc(shortSubj)}\n`;
      msg += `    _${esc(e.sender)}_\n`;
    }
    if (group.items.length > 5) {
      msg += `  _...+${group.items.length - 5} more_\n`;
    }
  }

  const actionCount = (groups['Urgent']?.items.length || 0) + (groups['Action Required']?.items.length || 0);
  if (actionCount > 0) {
    msg += `\n⚠️ *${actionCount} email${actionCount > 1 ? 's' : ''} need${actionCount === 1 ? 's' : ''} your attention*\n`;
  }
}

msg += `\n[Open Gmail](https://mail.google.com/mail/u/0/#inbox)`;

return [{ json: { reminderMessage: msg, messageType: 'email_digest' } }];

const CONFIG = {
  timezone: 'Asia/Jerusalem',
  reminderWindowDays: 7,
  maxPreviewLength: 250,
  urgencyKeywords: {
    critical: ['urgent', 'asap', 'immediately', 'critical', 'emergency', 'overdue', 'expired', 'דחוף', 'מיידי'],
    high: ['deadline', 'due', 'must', 'required', 'payment', 'expires', 'invoice', 'תאריך יעד', 'תשלום', 'חשבונית'],
    medium: ['meeting', 'call', 'reminder', 'review', 'submit', 'approval', 'פגישה', 'תזכורת', 'אישור'],
    low: ['fyi', 'update', 'info', 'notice', 'newsletter', 'עדכון']
  }
};

const out = [];
const now = Date.now();
const stats = { processed: 0, sent: 0, skipped: 0, errors: 0 };

const items = $input.all();
if (items.length === 1 && items[0].json?.error) {
  return [{ json: { source: 'email', error: true, errorMessage: items[0].json.error } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.emailReminders) staticData.emailReminders = {};
const sentEmails = staticData.emailReminders;

const cutoff = now - (CONFIG.reminderWindowDays * 86400000);
for (const [id, ts] of Object.entries(sentEmails)) {
  if (ts < cutoff) delete sentEmails[id];
}

function extractDates(text) {
  const dates = [];
  const patterns = [
    /\b(\d{1,2})[\/-](\d{1,2})[\/-](\d{2,4})\b/g,
    /\b(\d{4})[\/-](\d{1,2})[\/-](\d{1,2})\b/g,
    /\b(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\s+(\d{1,2}),?\s+(\d{4})?/gi,
    /\b(\d{1,2})\s+(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*,?\s+(\d{4})?/gi,
    /\b(today|tomorrow|monday|tuesday|wednesday|thursday|friday|saturday|sunday)\b/gi
  ];
  for (const p of patterns) {
    for (const m of text.matchAll(p)) dates.push(m[0]);
  }
  return [...new Set(dates)];
}

function getUrgency(text, dates) {
  const lower = text.toLowerCase();
  if (CONFIG.urgencyKeywords.critical.some(w => lower.includes(w)))
    return { emoji: '🔴', label: 'CRITICAL', priority: 4 };
  for (const d of dates) {
    const parsed = Date.parse(d);
    if (!isNaN(parsed)) {
      const days = (parsed - now) / 86400000;
      if (days >= 0 && days < 1) return { emoji: '🔴', label: 'TODAY', priority: 4 };
      if (days < 2) return { emoji: '🟡', label: 'TOMORROW', priority: 3 };
    }
  }
  if (CONFIG.urgencyKeywords.high.some(w => lower.includes(w)))
    return { emoji: '🔴', label: 'HIGH', priority: 3 };
  if (CONFIG.urgencyKeywords.medium.some(w => lower.includes(w)))
    return { emoji: '🟡', label: 'MEDIUM', priority: 2 };
  if (CONFIG.urgencyKeywords.low.some(w => lower.includes(w)))
    return { emoji: '🟢', label: 'LOW', priority: 1 };
  return { emoji: '⚪', label: 'INFO', priority: 0 };
}

function getSender(item) {
  let from = item.json.from || item.json.From || '';
  if ((!from || !from.includes('@')) && item.json.payload?.headers) {
    const h = item.json.payload.headers.find(h => h.name?.toLowerCase() === 'from');
    if (h?.value) from = h.value;
  }
  const nameMatch = from.match(/^([^<]+)\s*</);
  const emailMatch = from.match(/<([^>]+)>/);
  return {
    name: nameMatch ? nameMatch[1].trim() : 'Unknown',
    email: emailMatch ? emailMatch[1].trim() : (from.includes('@') ? from.trim() : 'unknown')
  };
}

function esc(text) {
  return (text || '').replace(/([\[\]_*`~])/g, '\\$1');
}

for (const item of items) {
  try {
    stats.processed++;
    const emailId = item.json.id || '';
    if (sentEmails[emailId] && (now - sentEmails[emailId]) < CONFIG.reminderWindowDays * 86400000) {
      stats.skipped++;
      continue;
    }
    const subjectRaw = item.json.subject || 'No Subject';
    const snippet = item.json.snippet || '';
    const fullText = `${subjectRaw} ${snippet}`;
    const sender = getSender(item);
    const dates = extractDates(fullText);
    const urgency = getUrgency(fullText, dates);
    if (urgency.priority < 2 && dates.length === 0) { stats.skipped++; continue; }

    let eventDate = null, daysUntil = null;
    for (const d of dates) {
      const parsed = Date.parse(d);
      if (!isNaN(parsed) && parsed > now) {
        eventDate = new Date(parsed).toLocaleDateString('en-GB', { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' });
        daysUntil = Math.ceil((parsed - now) / 86400000);
        break;
      }
    }

    const preview = snippet.length > CONFIG.maxPreviewLength ? snippet.substring(0, CONFIG.maxPreviewLength - 3) + '...' : snippet;

    let msg = `${urgency.emoji} *${urgency.label} - Email*\n`;
    msg += `\n📧 *Subject:* ${esc(subjectRaw)}\n`;
    msg += `👤 *From:* ${esc(sender.name)} (${esc(sender.email)})\n`;
    if (eventDate) {
      msg += `📅 *Date:* ${eventDate}`;
      if (daysUntil !== null) msg += ` (${daysUntil}d)`;
      msg += `\n`;
    }
    if (dates.length > 1) msg += `📌 *Other dates:* ${dates.slice(1, 3).join(', ')}\n`;
    msg += `\n_${esc(preview)}_\n`;
    msg += `\n[Open in Gmail](https://mail.google.com/mail/u/0/#inbox/${emailId})`;

    sentEmails[emailId] = now;
    stats.sent++;
    out.push({ json: { source: 'email', reminderMessage: msg, shouldSendReminder: true, emailId, subject: subjectRaw, priority: urgency.priority, timestamp: now } });
  } catch (e) {
    stats.errors++;
    console.error(`Email error: ${e.message}`);
  }
}

console.log(`Email: ${stats.processed} processed, ${stats.sent} sent, ${stats.skipped} skipped, ${stats.errors} errors`);
return out.length > 0 ? out : [{ json: { shouldSendReminder: false, source: 'email' } }];

const CONFIG = {
  timezone: 'Asia/Jerusalem',
  deduplicationHours: 24,
  reminderWindows: [
    { max: 180, min: 61, label: '~2 hours' },
    { max: 60, min: 31, label: '1 hour' },
    { max: 30, min: 16, label: '30 minutes' },
    { max: 15, min: 6, label: '15 minutes' },
    { max: 5, min: 0, label: 'Starting NOW' }
  ]
};

const out = [];
const now = Date.now();
const stats = { processed: 0, sent: 0, skipped: 0, errors: 0 };

const items = $input.all();
if (items.length === 1 && items[0].json?.error) {
  return [{ json: { source: 'calendar', error: true, errorMessage: items[0].json.error } }];
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.calendarEvents) staticData.calendarEvents = {};
const sent = staticData.calendarEvents;

const cutoff = now - (CONFIG.deduplicationHours * 3600000);
for (const [k, ts] of Object.entries(sent)) {
  if (ts < cutoff) delete sent[k];
}

function getWindow(mins) {
  for (const w of CONFIG.reminderWindows) {
    if (mins <= w.max && mins >= w.min) return w;
  }
  return null;
}

function getMeetingInfo(ev) {
  if (ev.hangoutLink) return { hasVideo: true, platform: 'Google Meet', link: ev.hangoutLink };
  const loc = (ev.location || '').toLowerCase();
  if (loc.includes('zoom')) return { hasVideo: true, platform: 'Zoom', link: ev.location.match(/https?:\/\/[^\s]+zoom[^\s]+/i)?.[0] || ev.location };
  if (loc.includes('teams.microsoft')) return { hasVideo: true, platform: 'Teams', link: ev.location.match(/https?:\/\/[^\s]+teams[^\s]+/i)?.[0] || ev.location };
  return { hasVideo: false, platform: null, link: null };
}

function esc(text) {
  return (text || '').replace(/([\[\]_*`~])/g, '\\$1');
}

for (const item of items) {
  try {
    stats.processed++;
    const ev = item.json;
    const eventId = ev.id || '';
    const startISO = ev.start?.dateTime || ev.start?.date;
    if (!startISO) { stats.skipped++; continue; }

    const startDate = new Date(startISO);
    const minsUntil = Math.floor((startDate - now) / 60000);
    if (minsUntil < 0 || minsUntil > 180) { stats.skipped++; continue; }

    const win = getWindow(minsUntil);
    if (!win) { stats.skipped++; continue; }

    const key = `${eventId}_${win.label}`;
    if (sent[key]) { stats.skipped++; continue; }

    const meeting = getMeetingInfo(ev);
    const fmtTime = (iso) => iso ? new Date(iso).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', timeZone: CONFIG.timezone }) : null;
    const startTime = fmtTime(startISO);
    const endTime = fmtTime(ev.end?.dateTime || ev.end?.date);

    const attendees = (ev.attendees || [])
      .filter(a => !a.self && a.responseStatus !== 'declined')
      .map(a => {
        const name = a.displayName || a.email?.split('@')[0] || '?';
        const icon = a.responseStatus === 'accepted' ? '✓' : a.responseStatus === 'tentative' ? '?' : '';
        return icon ? `${name}${icon}` : name;
      }).slice(0, 5);

    const urgencyEmoji = minsUntil <= 5 ? '🔴' : minsUntil <= 15 ? '🟠' : minsUntil <= 30 ? '🟡' : '🟢';
    const priority = minsUntil <= 5 ? 5 : minsUntil <= 15 ? 4 : minsUntil <= 30 ? 3 : 2;

    let msg = `${urgencyEmoji} *${win.label} - Calendar*\n`;
    msg += `\n📅 *${esc(ev.summary || 'Untitled Event')}*\n`;
    msg += `🕒 ${startTime}${endTime ? ' - ' + endTime : ''} (in ${minsUntil}min)\n`;
    if (ev.organizer && !ev.organizer.self) msg += `👔 ${esc(ev.organizer.displayName || ev.organizer.email?.split('@')[0])}\n`;
    if (attendees.length > 0) {
      msg += `👥 ${attendees.join(', ')}`;
      if ((ev.attendees || []).length > 5) msg += ` +${ev.attendees.length - 5}`;
      msg += `\n`;
    }
    if (!meeting.hasVideo && ev.location) msg += `📍 ${esc(ev.location)}\n`;
    if (meeting.hasVideo) msg += `\n🎥 [Join ${meeting.platform}](${meeting.link})\n`;
    if (ev.htmlLink) msg += `[View in Calendar](${ev.htmlLink})`;

    sent[key] = now;
    stats.sent++;
    out.push({ json: { source: 'calendar', reminderMessage: msg, shouldSendReminder: true, eventId, priority, timestamp: now } });
  } catch (e) {
    stats.errors++;
    console.error(`Calendar error: ${e.message}`);
  }
}

console.log(`Calendar: ${stats.processed} processed, ${stats.sent} sent, ${stats.skipped} skipped, ${stats.errors} errors`);
return out.length > 0 ? out : [{ json: { shouldSendReminder: false, source: 'calendar' } }];

const items = $input.all();
items.sort((a, b) => (b.json.priority || 0) - (a.json.priority || 0));
const MAX_PER_RUN = 5;
if (items.length > MAX_PER_RUN) {
  console.log(`Rate limiting: ${items.length} reminders, sending top ${MAX_PER_RUN}`);
  return items.slice(0, MAX_PER_RUN);
}
return items;

const staticData = $getWorkflowStaticData('global');
if (!staticData.deliveryLog) staticData.deliveryLog = [];
if (!staticData.failedQueue) staticData.failedQueue = [];
if (!staticData.dailyStats) staticData.dailyStats = { date: '', sent: 0, failed: 0, retried: 0 };

const now = Date.now();
const todayStr = new Date(now).toISOString().slice(0, 10);
const result = $json;
const originalMsg = $('Sort & Rate Limit').item.json;
const success = !result.error && result.message_id;

// Reset daily stats at midnight
if (staticData.dailyStats.date !== todayStr) {
  staticData.yesterdayStats = { ...staticData.dailyStats };
  staticData.dailyStats = { date: todayStr, sent: 0, failed: 0, retried: 0 };
}

// Log delivery
staticData.deliveryLog.push({ timestamp: now, success, source: originalMsg.source, subject: originalMsg.subject || originalMsg.eventId || 'unknown' });
if (staticData.deliveryLog.length > 100) staticData.deliveryLog = staticData.deliveryLog.slice(-100);

const outputs = [];

if (success) {
  staticData.dailyStats.sent++;
} else {
  staticData.dailyStats.failed++;
  staticData.failedQueue.push({
    message: originalMsg.reminderMessage,
    source: originalMsg.source,
    attempt: 1,
    maxAttempts: 3,
    queuedAt: now,
    lastError: JSON.stringify(result).substring(0, 200)
  });
  console.error('Send failed, queued for retry');
}

// Process retry queue
const stillWaiting = [];
for (const item of staticData.failedQueue) {
  const waitMs = item.attempt * 60000;
  if (now - item.queuedAt >= waitMs && item.attempt <= item.maxAttempts) {
    item.attempt++;
    item.queuedAt = now;
    staticData.dailyStats.retried++;
    outputs.push({ json: { reminderMessage: '🔄 *Retry (attempt ' + item.attempt + '/' + item.maxAttempts + ')*\n\n' + item.message, isRetry: true } });
    if (item.attempt <= item.maxAttempts) stillWaiting.push(item);
  } else if (item.attempt <= item.maxAttempts) {
    stillWaiting.push(item);
  } else {
    console.error('Permanently failed after ' + item.maxAttempts + ' attempts: ' + item.source);
  }
}
staticData.failedQueue = stillWaiting;

// Daily summary at ~8 AM Israel time
const israelHour = parseInt(new Date(now).toLocaleString('en-GB', { hour: 'numeric', hour12: false, timeZone: 'Asia/Jerusalem' }));
if (israelHour === 8 && staticData.yesterdayStats?.date) {
  if (!staticData.dailySummarySent) staticData.dailySummarySent = {};
  if (!staticData.dailySummarySent[todayStr]) {
    const ys = staticData.yesterdayStats;
    if (ys.sent > 0 || ys.failed > 0) {
      const rate = ys.sent + ys.failed > 0 ? Math.round((ys.sent / (ys.sent + ys.failed)) * 100) : 100;
      let summary = '📊 *Daily Reminder Summary*\n';
      summary += '\n✅ Sent: ' + ys.sent;
      summary += '\n❌ Failed: ' + ys.failed;
      if (ys.retried > 0) summary += '\n🔄 Retried: ' + ys.retried;
      summary += '\n📈 Success rate: ' + rate + '%';
      if (ys.failed > 0) {
        const fails = staticData.deliveryLog.filter(l => !l.success).slice(-3).map(l => '  • ' + l.source + ': ' + l.subject).join('\n');
        if (fails) summary += '\n\n⚠️ *Recent failures:*\n' + fails;
      }
      outputs.push({ json: { reminderMessage: summary, isDailySummary: true } });
      staticData.dailySummarySent[todayStr] = true;
    }
  }
  // Clean old flags
  for (const d of Object.keys(staticData.dailySummarySent || {})) {
    if (d < new Date(now - 259200000).toISOString().slice(0, 10)) delete staticData.dailySummarySent[d];
  }
}

// Clean old failed queue items
staticData.failedQueue = staticData.failedQueue.filter(i => now - i.queuedAt < 86400000);

return outputs.length > 0 ? outputs : [{ json: { delivered: success, noAction: true } }];
